CREATE DATABASE IF NOT EXISTS chupahub CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;USE chupahub;
CREATE TABLE users(id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(120) NOT NULL,email VARCHAR(190) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,role ENUM('customer','admin','driver') DEFAULT 'customer',loyalty_points INT DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE categories(id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(120) NOT NULL,slug VARCHAR(140) UNIQUE NOT NULL,icon VARCHAR(40),is_active BOOLEAN DEFAULT TRUE);
CREATE TABLE brands(id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(140) NOT NULL,slug VARCHAR(160) UNIQUE NOT NULL,country VARCHAR(80));
CREATE TABLE products(id BIGINT PRIMARY KEY AUTO_INCREMENT,category_id BIGINT NOT NULL,brand_id BIGINT NOT NULL,slug VARCHAR(190) UNIQUE NOT NULL,name VARCHAR(190) NOT NULL,description TEXT,abv DECIMAL(5,2),country VARCHAR(80),bottle_size VARCHAR(40),price DECIMAL(12,2) NOT NULL,old_price DECIMAL(12,2),stock INT DEFAULT 0,barcode VARCHAR(120),is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FULLTEXT(name,description),INDEX(category_id),INDEX(brand_id),INDEX(price),FOREIGN KEY(category_id) REFERENCES categories(id),FOREIGN KEY(brand_id) REFERENCES brands(id));
CREATE TABLE product_images(id BIGINT PRIMARY KEY AUTO_INCREMENT,product_id BIGINT NOT NULL,url VARCHAR(500) NOT NULL,sort_order INT DEFAULT 0,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE);
CREATE TABLE addresses(id BIGINT PRIMARY KEY AUTO_INCREMENT,user_id BIGINT NOT NULL,label VARCHAR(80),line1 VARCHAR(190),city VARCHAR(90),gps_lat DECIMAL(10,7),gps_lng DECIMAL(10,7),FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE orders(id BIGINT PRIMARY KEY AUTO_INCREMENT,user_id BIGINT NOT NULL,status ENUM('pending','paid','packing','out_for_delivery','completed','cancelled','refunded') DEFAULT 'pending',total DECIMAL(12,2),delivery_fee DECIMAL(10,2),payment_method VARCHAR(40),gps_lat DECIMAL(10,7),gps_lng DECIMAL(10,7),gift_note TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE order_items(id BIGINT PRIMARY KEY AUTO_INCREMENT,order_id BIGINT,product_id BIGINT,quantity INT,unit_price DECIMAL(12,2),FOREIGN KEY(order_id) REFERENCES orders(id),FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE delivery_charges(id INT PRIMARY KEY AUTO_INCREMENT,min_km DECIMAL(6,2),max_km DECIMAL(6,2),fee DECIMAL(10,2));INSERT INTO delivery_charges(min_km,max_km,fee) VALUES(0,5,150),(5,10,250),(10,12,350),(12,9999,500);
CREATE TABLE coupons(id BIGINT PRIMARY KEY AUTO_INCREMENT,code VARCHAR(80) UNIQUE,type ENUM('percent','fixed'),value DECIMAL(10,2),starts_at DATETIME,ends_at DATETIME,is_active BOOLEAN DEFAULT TRUE);
CREATE TABLE audit_logs(id BIGINT PRIMARY KEY AUTO_INCREMENT,user_id BIGINT,action VARCHAR(160),payload JSON,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE OR REPLACE VIEW product_view AS SELECT p.*,b.name brand,c.slug category,(SELECT JSON_ARRAYAGG(url) FROM product_images WHERE product_id=p.id) images FROM products p JOIN brands b ON b.id=p.brand_id JOIN categories c ON c.id=p.category_id;
